  1→import React, { useCallback, useEffect, useRef, useState } from "react";
  2→import "./myprofile.css";
  3→import { useAuth } from "../../Context/useAuth";
  4→import { Outlet, useLocation, useNavigate } from "react-router-dom";
  5→import Sidebar from "../SideBar/Sidebar";
  6→import { updateFontColor, updateProfileData } from "../../../API/Api";
  7→import { AnimatePresence } from "framer-motion";
  8→import { useQueryClient } from "@tanstack/react-query";
  9→import Editor from "../HomePage/Editor/Editor";
 10→import getCroppedImage from "../../utils/getCroppedImage";
 11→import extractDominantColors from "../../utils/extractDominantColors";
 12→import MobileNavlink from "../mobileNavLink/MobileNavLink";
 13→import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
 14→import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
 15→import Loader from "../loadingComponent/BgLoader";
 16→import ProfileBackgroundPicker from "./components/ProfileBackgroundPicker";
 17→import ProfileEditModal from "./components/ProfileEditModal";
 18→import ProfileFontColorSelector from "./components/ProfileFontColorSelector";
 19→import ProfileHeroSection from "./components/ProfileHeroSection";
 20→import ProfileTabList from "./components/ProfileTabList";
 21→import { PROFILE_GRADIENTS } from "./constants/profileGradients";
 22→import { createProfileSidebarLinks } from "./constants/profileSidebarLinks";
 23→import { PROFILE_TABS } from "./constants/profileTabs";
 24→
 25→const MyProfile = () => {
 26→    const { user, session, isLoading, notifCount, loading } = useAuth();
 27→
 28→    const userData = user?.userData?.[0];
 29→
 30→    const [showMobileSideBar, setShowMobileSideBar] = useState(false);
 31→
 32→    const [showProfileEditor, setShowProfileEditor] = useState(false);
 33→    const [editImagePreview, setEditImagePreview] = useState("");
 34→    const [profileEditAvatar, setProfileEditAvatar] = useState(null);
 35→    const [profileEditName, setProfileEditName] = useState("");
 36→    const [profileEditBio, setProfileEditBio] = useState("");
 37→
 38→    const [showEditor, setShowEditor] = useState(false);
 39→    const [showBgPicker, setShowBgPicker] = useState(false);
 40→
 41→    const [imageSrc, setImageSrc] = useState(null);
 42→    const [crop, setCrop] = useState({ x: 0, y: 0 });
 43→    const [zoom, setZoom] = useState(1);
 44→    const [croppedAreaPixels, setCropAreaPixels] = useState(null);
 45→    const [gradientPicked, setGradientPicked] = useState(null);
 46→    const [croppedImage, setCroppedImage] = useState({});
 47→
 48→    const [showFontColorSelector, setShowFontColorSelector] = useState(false);
 49→    const [fontColor, setFontColor] = useState("");
 50→
 51→    const inputRef = useRef();
 52→    const bgInputRef = useRef();
 53→    const fontColorInputRef = useRef();
 54→
 55→    const [dominantColors, setDominantColors] = useState("#ffffffff");
 56→    const [secondaryColors, setSecondaryColors] = useState("#ffffffff");
 57→
 58→    const [isUpdatingFont, setIsUpdatingFont] = useState(false);
 59→    const [isUpdatingProfileConfig, setIsUpdatingProfileConfig] = useState(false);
 60→    const [isSavingProfile, setIsSavingProfile] = useState(false);
 61→    const [saveError, setSaveError] = useState("");
 62→
 63→    const navigate = useNavigate();
 64→    const navigatePath = (path) => {
 65→        return navigate(path);
 66→    };
 67→    const location = useLocation();
 68→
 69→    const queryClient = useQueryClient();
 70→
 71→    const links = createProfileSidebarLinks({
 72→        location,
 73→        navigatePath,
 74→        navigate,
 75→        notifCount,
 76→        setShowEditor,
 77→    });
 78→    const gradients = PROFILE_GRADIENTS;
 79→    const tablists = PROFILE_TABS;
 80→
 81→    useEffect(() => {
 82→        setCroppedImage(userData?.background || null);
 83→        setFontColor(userData?.profile_font_color || "");
 84→    }, [userData?.background, userData?.profile_font_color]);
 85→
 86→    const showError = (msg) => {
 87→        setSaveError(msg);
 88→        setTimeout(() => setSaveError(""), 4000);
 89→    };
 90→
 91→    const openRichTextEditor = () => {
 92→        setShowEditor(true);
 93→    };
 94→
 95→    const handleClickOpenSidebar = () => {
 96→        setShowMobileSideBar(true);
 97→    };
 98→
 99→    const handleCloseSidebar = () => {
100→        setShowMobileSideBar(false);
101→    };
102→
103→    const handleClickEdit = (e) => {
104→        e.stopPropagation();
105→        setShowFontColorSelector(false);
106→        setEditImagePreview(userData?.image_url);
107→        setProfileEditName(userData?.name);
108→        setProfileEditBio(userData?.bio);
109→        setShowProfileEditor(true);
110→    };
111→
112→    const closeEditor = (e) => {
113→        e.stopPropagation();
114→        setEditImagePreview("");
115→        handleHideGradientPicker(e);
116→        setImageSrc(null);
117→        setProfileEditAvatar(null);
118→        setShowProfileEditor(false);
119→    };
120→
121→    const handleCloseRichTextEditor = useCallback(() => {
122→        setShowEditor(false);
123→    }, []);
124→
125→    const handleImageOnChange = (e) => {
126→        const file = e.target.files[0];
127→        if (file) {
128→            setProfileEditAvatar(file);
129→            const reader = new FileReader();
130→            reader.onloadend = () => {
131→                setEditImagePreview(reader.result);
132→            };
133→
134→            reader.readAsDataURL(file);
135→        } else {
136→            setEditImagePreview("");
137→        }
138→    };
139→
140→    const insertImageFromFile = (e) => {
141→        e.stopPropagation();
142→        if (inputRef.current) {
143→            inputRef.current.click();
144→        }
145→    };
146→
147→    const handleShowGradientPicker = (e) => {
148→        e.stopPropagation();
149→        setShowBgPicker(true);
150→    };
151→
152→    const handleHideGradientPicker = (e) => {
153→        e.stopPropagation();
154→        setShowBgPicker(false);
155→        setCroppedImage(userData?.background);
156→        setImageSrc(null);
157→        setGradientPicked(null);
158→    };
159→
160→    const handleSaveProfileEdit = async () => {
161→        if (isSavingProfile) return;
162→        setIsSavingProfile(true);
163→        const data = {
164→            name: profileEditName,
165→            image: profileEditAvatar,
166→            bio: profileEditBio,
167→            profileBg: croppedImage,
168→            dominantColors: dominantColors,
169→            secondaryColors: secondaryColors,
170→        };
171→
172→        try {
173→            const formdata = new FormData();
174→            Object.entries(data).forEach(([key, value]) => {
175→                if (value === undefined || value === null) {
176→                    return;
177→                }
178→                if (typeof value === "object" && value !== null && !(value instanceof File)) {
179→                    formdata.append(key, JSON.stringify(value));
180→                    return;
181→                }
182→
183→                formdata.append(key, value);
184→            });
185→
186→            await updateProfileData(formdata, session?.access_token);
187→            setProfileEditAvatar(null);
188→            queryClient.invalidateQueries({ queryKey: ["userData"] });
189→            setShowProfileEditor(false);
190→        } catch {
191→            showError("Failed to save profile. Please try again.");
192→        } finally {
193→            setIsSavingProfile(false);
194→        }
195→    };
196→
197→    const handleSaveProfileConfig = async () => {
198→        if (isUpdatingProfileConfig) return;
199→        setIsUpdatingProfileConfig(true);
200→        try {
201→            if (imageSrc) {
202→                const croppedImageUrl = await getCroppedImage(imageSrc, croppedAreaPixels, userData.id, session?.access_token);
203→                if (croppedImageUrl) {
204→                    setCroppedImage({
205→                        backgroundImage: `url(${croppedImageUrl?.url})`,
206→                        backgroundSize: "cover",
207→                        backgroundPosition: "center",
208→                        backgroundRepeat: "no-repeat",
209→                    });
210→                }
211→            } else if (gradientPicked) {
212→                setCroppedImage(gradientPicked);
213→            }
214→            setGradientPicked(null);
215→            setImageSrc(null);
216→            setShowBgPicker(false);
217→            queryClient.invalidateQueries({ queryKey: ["userData"] });
218→        } catch {
219→            showError("Failed to update background. Please try again.");
220→        } finally {
221→            setIsUpdatingProfileConfig(false);
222→        }
223→    };
224→
225→    const handleRemoveBgPreview = () => {
226→        setImageSrc(null);
227→    };
228→
229→    const handleSelectGradient = useCallback((gradient) => {
230→        setCroppedImage(null);
231→        setImageSrc(null);
232→        setGradientPicked(gradient);
233→    }, []);
234→
235→    const handleInsertBgImage = (e) => {
236→        e.stopPropagation();
237→        if (bgInputRef.current) {
238→            bgInputRef.current.value = "";
239→            bgInputRef.current.click();
240→        }
241→    };
242→
243→    const handleBgOnchange = (e) => {
244→        const file = e.target.files[0];
245→        if (file) {
246→            const reader = new FileReader();
247→            reader.onloadend = () => {
248→                const img = new Image();
249→                img.crossOrigin = "anonymous";
250→
251→                img.src = reader.result;
252→
253→                img.onload = () => {
254→                    const colors = extractDominantColors(img);
255→                    setDominantColors(colors.primary);
256→                    setSecondaryColors(colors.secondary);
257→                };
258→
259→                setImageSrc(reader.result);
260→            };
261→
262→            reader.readAsDataURL(file);
263→        } else {
264→            return setGradientPicked({});
265→        }
266→    };
267→
268→    const handleClickFontColorSelector = (e) => {
269→        e.stopPropagation();
270→        setShowFontColorSelector(true);
271→    };
272→
273→    const handleClickInputColor = () => {
274→        if (fontColorInputRef.current) {
275→            fontColorInputRef.current.click();
276→        }
277→    };
278→
279→    const handleClickSaveFontColor = async () => {
280→        if (isUpdatingFont) return;
281→        setIsUpdatingFont(true);
282→        const formdata = new FormData();
283→        formdata.append("fontColor", fontColor);
284→        try {
285→            await updateFontColor(session?.access_token, formdata);
286→            queryClient.invalidateQueries({ queryKey: ["userData"] });
287→            setShowFontColorSelector(false);
288→        } catch {
289→            showError("Failed to update font color. Please try again.");
290→        } finally {
291→            setIsUpdatingFont(false);
292→        }
293→    };
294→
295→    const handleClickCancelFontSelect = () => {
296→        setShowFontColorSelector(false);
297→        setFontColor(userData?.profile_font_color || "");
298→    };
299→
300→    useEffect(() => {
301→        if (!session && !loading) {
302→            return navigate("/login");
303→        }
304→    }, [session, loading, navigate]);
305→
306→    if (isLoading) {
307→        return <Loader />;
308→    }
309→
310→    return (
311→        <>
312→            <ProfileFontColorSelector
313→                show={showFontColorSelector}
314→                fontColor={fontColor}
315→                fontColorInputRef={fontColorInputRef}
316→                setFontColor={setFontColor}
317→                handleClickInputColor={handleClickInputColor}
318→                handleClickCancelFontSelect={handleClickCancelFontSelect}
319→                handleClickSaveFontColor={handleClickSaveFontColor}
320→                isUpdatingFont={isUpdatingFont}
321→            />
322→            <ProfileBackgroundPicker
323→                show={showBgPicker}
324→                handleBgOnchange={handleBgOnchange}
325→                bgInputRef={bgInputRef}
326→                gradients={gradients}
327→                gradientPicked={gradientPicked}
328→                handleSelectGradient={handleSelectGradient}
329→                handleInsertBgImage={handleInsertBgImage}
330→                imageSrc={imageSrc}
331→                crop={crop}
332→                zoom={zoom}
333→                setCrop={setCrop}
334→                setZoom={setZoom}
335→                setCropAreaPixels={setCropAreaPixels}
336→                handleRemoveBgPreview={handleRemoveBgPreview}
337→                handleHideGradientPicker={handleHideGradientPicker}
338→                handleSaveProfileConfig={handleSaveProfileConfig}
339→                isUpdatingProfileConfig={isUpdatingProfileConfig}
340→            />
341→            <AnimatePresence>
342→                <ProfileEditModal
343→                    key={"profile-edit-modal"}
344→                    showProfileEditor={showProfileEditor}
345→                    closeEditor={closeEditor}
346→                    croppedImage={croppedImage}
347→                    gradientPicked={gradientPicked}
348→                    insertImageFromFile={insertImageFromFile}
349→                    handleImageOnChange={handleImageOnChange}
350→                    inputRef={inputRef}
351→                    editImagePreview={editImagePreview}
352→                    userData={userData}
353→                    handleShowGradientPicker={handleShowGradientPicker}
354→                    profileEditName={profileEditName}
355→                    setProfileEditName={setProfileEditName}
356→                    profileEditBio={profileEditBio}
357→                    setProfileEditBio={setProfileEditBio}
358→                    handleSaveProfileEdit={handleSaveProfileEdit}
359→                    isSavingProfile={isSavingProfile}
360→                />
361→
362→                {showEditor && <Editor key={"main-editor"} onClose={handleCloseRichTextEditor} />}
363→
364→                <div
365→                    key={"profile-page-layout"}
366→                    className="profile-parent-container"
367→                    style={croppedImage ? { background: `linear-gradient(135deg, ${dominantColors}0%, ${secondaryColors} 100%)` } : gradientPicked}
368→                >
369→                    {gradientPicked && <div className="blurred-gradient-bg" style={gradientPicked} />}
370→
371→                    {croppedImage && <div style={croppedImage} className="blurred-img-bg" />}
372→
373→                    <div className="side-bar-holder-container">
374→                        <Sidebar links={links} />
375→                    </div>
376→
377→                    <div style={{ color: fontColor || userData?.profile_font_color }} className="profile-center-bar-container">
378→                        <ProfileHeroSection
379→                            userData={userData}
380→                            user={user}
381→                            fontColor={fontColor}
382→                            handleClickEdit={handleClickEdit}
383→                            handleClickFontColorSelector={handleClickFontColorSelector}
384→                            croppedImage={croppedImage}
385→                            gradientPicked={gradientPicked}
386→                        />
387→
388→                        <ProfileTabList tablists={tablists} navigate={navigate} location={location} />
389→
390→                        <Outlet />
391→                    </div>
392→
393→                    <div className="profile-sidebar-right-holder-container">{/* Log out */}</div>
394→
395→                    {showMobileSideBar && <MobileSidebarLink onclose={handleCloseSidebar} />}
396→
397→                    <MobileNavlink clickOpenSidebar={handleClickOpenSidebar} />
398→                    <WriteJournalButton onOpen={openRichTextEditor} />
399→                </div>
400→            </AnimatePresence>
401→
402→            {saveError && (
403→                <div key={saveError} className="profile-save-error-toast">
404→                    {saveError}
405→                </div>
406→            )}
407→        </>
408→    );
409→};
410→
411→export default MyProfile;
