  1→import { useEffect } from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useUserStories } from '../../Stories/hooks/useStoryData';
  5→import { useInView } from 'react-intersection-observer';
  6→import { motion } from 'framer-motion';
  7→import { MoonLoader } from 'react-spinners';
  8→import './ProfileStoriesSection.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→
 12→const ProfileStoriesSection = () => {
 13→    const { user, session } = useAuth();
 14→    const token = session?.access_token;
 15→    const userId = user?.userData?.[0]?.id;
 16→    const navigate = useNavigate();
 17→
 18→    const { ref, inView } = useInView({ threshold: 0.2 });
 19→
 20→    const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } = useUserStories(userId, token);
 21→    const stories = data?.pages?.flatMap(page => page.data) || [];
 22→
 23→    const isLoadingMore = isFetchingNextPage || !hasNextPage;
 24→    useEffect(() => {
 25→        if (inView && !isLoadingMore) {
 26→            fetchNextPage();
 27→        }
 28→    }, [fetchNextPage, isLoadingMore, inView]);
 29→
 30→    if (isLoading) {
 31→        return (
 32→            <div className="profile-postcards-loading-container">
 33→                <MoonLoader loading={true} color="var(--loader-color)" size={20} speedMultiplier={0.5} />
 34→            </div>
 35→        );
 36→    }
 37→
 38→    return (
 39→        <div className="profile-stories-section">
 40→            <div className="profile-stories-header-row">
 41→                <h2 className="profile-stories-heading">
 42→                    Stories <span className="profile-stories-count">({stories.length})</span>
 43→                </h2>
 44→            </div>
 45→
 46→            {!stories.length ? (
 47→                <div className="profile-stories-empty">
 48→                    <svg className="profile-stories-empty-icon" xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="currentColor">
 49→                        <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 50→                    </svg>
 51→                    <p className="profile-stories-empty-text">No stories yet.</p>
 52→                </div>
 53→            ) : (
 54→                <div className="profile-stories-list">
 55→                    {stories.map((story, index) => (
 56→                        <motion.div
 57→                            key={story.id}
 58→                            className="profile-story-card"
 59→                            initial={{ opacity: 0, y: 12 }}
 60→                            animate={{ opacity: 1, y: 0 }}
 61→                            transition={{ duration: 0.3, ease: 'easeOut', delay: index * 0.04 }}
 62→                            onClick={() => navigate(`/home/stories/${story.id}`)}
 63→                        >
 64→                            <div className="profile-story-cover">
 65→                                {story.cover_url ? (
 66→                                    <img src={story.cover_url} alt={story.title} loading="lazy" />
 67→                                ) : (
 68→                                    <div className="profile-story-cover-placeholder">
 69→                                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="var(--text-muted)" opacity="0.4">
 70→                                            <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z" />
 71→                                        </svg>
 72→                                    </div>
 73→                                )}
 74→                            </div>
 75→                            <div className="profile-story-body">
 76→                                <h3 className="profile-story-title">{story.title}</h3>
 77→                                {story.description && (
 78→                                    <p className="profile-story-description">{story.description}</p>
 79→                                )}
 80→                                <div className="profile-story-meta">
 81→                                    <span className={`profile-story-badge profile-story-badge-${story.status}`}>
 82→                                        {STATUS_LABELS[story.status] || story.status}
 83→                                    </span>
 84→                                    <span className="profile-story-stats">
 85→                                        {story.vote_count || 0} votes &middot; {story.read_count || 0} reads
 86→                                    </span>
 87→                                </div>
 88→                                {story.tags && story.tags.length > 0 && (
 89→                                    <div className="profile-story-tags">
 90→                                        {story.tags.slice(0, 3).map(tag => (
 91→                                            <span key={tag} className="profile-story-tag">{tag}</span>
 92→                                        ))}
 93→                                    </div>
 94→                                )}
 95→                            </div>
 96→                        </motion.div>
 97→                    ))}
 98→                </div>
 99→            )}
100→
101→            <div ref={ref} className="in-view-container">
102→                {isFetchingNextPage && (
103→                    <MoonLoader loading={isFetchingNextPage} color="var(--loader-color)" size={20} />
104→                )}
105→            </div>
106→        </div>
107→    );
108→};
109→
110→export default ProfileStoriesSection;
