  1→import React from "react";
  2→import { AnimatePresence, motion as Motion } from "framer-motion";
  3→import { BarLoader } from "react-spinners";
  4→import Cropper from "react-easy-crop";
  5→
  6→const ProfileBackgroundPicker = ({
  7→    show,
  8→    handleBgOnchange,
  9→    bgInputRef,
 10→    gradients,
 11→    gradientPicked,
 12→    handleSelectGradient,
 13→    handleInsertBgImage,
 14→    imageSrc,
 15→    crop,
 16→    zoom,
 17→    setCrop,
 18→    setZoom,
 19→    setCropAreaPixels,
 20→    handleRemoveBgPreview,
 21→    handleHideGradientPicker,
 22→    handleSaveProfileConfig,
 23→    isUpdatingProfileConfig,
 24→}) => {
 25→    if (!show) {
 26→        return null;
 27→    }
 28→
 29→    return (
 30→        <AnimatePresence>
 31→            <Motion.div
 32→                initial={{ opacity: 0 }}
 33→                animate={{ opacity: 1 }}
 34→                exit={{ opacity: 0 }}
 35→                transition={{ type: "spring", stiffness: 250, damping: 25 }}
 36→                className="profile-bg-picker-container"
 37→            >
 38→                <div className="profile-bg-picker-header">Pick a gradient or add image</div>
 39→
 40→                <input
 41→                    onChange={(e) => handleBgOnchange(e)}
 42→                    style={{ display: "none" }}
 43→                    ref={bgInputRef}
 44→                    type="file"
 45→                    accept="image/*"
 46→                />
 47→
 48→                <div className="profile-bg-color-palette">
 49→                    {gradients.map((gradient, index) => {
 50→                        const isSelected =
 51→                            gradientPicked &&
 52→                            JSON.stringify(gradientPicked) === JSON.stringify(gradient.style);
 53→                        return (
 54→                            <div
 55→                                onClick={() => handleSelectGradient(gradient.style)}
 56→                                key={index}
 57→                                className={`gradient-box${isSelected ? " gradient-selected" : ""}`}
 58→                                style={gradient.style}
 59→                            ></div>
 60→                        );
 61→                    })}
 62→                </div>
 63→
 64→                <div className="profile-bg-preview">
 65→                    <div onClick={(e) => handleInsertBgImage(e)} className="add-bgImage-bttn">
